INSERT INTO usb_targets (target_id, name, route_tag_hex, product_id_hex, transport, description, source_id) VALUES (1, 'HeadUsbDirect', '0x01', '0x5741', 'UsbDeviceConnection.bulkTransfer(mEpBulkOut_Head)', 'Head MCU USB accessory endpoint. Route tag 1 is used when WHAT_SEND_TO_ALL strips a trailing route byte.', 4);
INSERT INTO usb_targets (target_id, name, route_tag_hex, product_id_hex, transport, description, source_id) VALUES (2, 'BottomUsbDirect', '0x02', '0x5740', 'UsbDeviceConnection.bulkTransfer(mEpBulkOut_Bottom)', 'Bottom MCU USB accessory endpoint. Route tag 2 is used when WHAT_SEND_TO_ALL strips a trailing route byte.', 4);
INSERT INTO usb_targets (target_id, name, route_tag_hex, product_id_hex, transport, description, source_id) VALUES (3, 'BothHeadAndBottom', '0x03', '0x5741/0x5740', 'Bulk transfer to both head and bottom endpoints', 'Route tag 3 sends the same packet body to both MCU endpoints.', 4);
INSERT INTO usb_targets (target_id, name, route_tag_hex, product_id_hex, transport, description, source_id) VALUES (4, 'CallerSelectedNoRouteTag', NULL, NULL, 'Message.what selects head or bottom directly', 'Command returns the USB packet without a trailing route tag; the caller must select WHAT_SEND_TO_HEAD or WHAT_SEND_TO_BOTTOM.', 4);
INSERT INTO usb_targets (target_id, name, route_tag_hex, product_id_hex, transport, description, source_id) VALUES (5, 'UpgradeCallbackSelected', NULL, '0x5741/0x5740', 'McuUpgradeManager.UpgradeCallback sendToHead/sendToBottom', 'Upgrade package commands return packet body only; the upgrade callback chooses head or bottom.', 2);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (1, 'UsbMcuPacket', 0, 1, 'OuterType', 2, 'big', 'shortToByteArray((short)0xA403)', 'Outer USB message type; constructor stores -0x5bfd, serialized as A4 03.', 1);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (2, 'UsbMcuPacket', 2, 3, 'Subtype', 2, 'big', '0x0000', 'Outer subtype, always zero in these builders.', 1);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (3, 'UsbMcuPacket', 4, 7, 'MessageSize', 4, 'big', 'integerToByteArray(payload_length + 6)', 'Content length from setMessageContent; for normal short payloads this is 00 00 00 len.', 1);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (4, 'UsbMcuPacket', 8, 8, 'OuterAckFlag', 1, 'n/a', 'ack_flg', 'Ack flag before the seven unused bytes.', 1);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (5, 'UsbMcuPacket', 9, 15, 'Unused', 7, 'n/a', '00 00 00 00 00 00 00', 'Seven-byte zero-filled unused area.', 1);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (6, 'UsbMcuPacket', 16, 17, 'FrameHead', 2, 'big', 'shortToByteArray((short)0xFFA5)', 'Inner frame header; constructor stores -0x5b, serialized as FF A5.', 1);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (7, 'UsbMcuPacket', 18, 18, 'InnerAckFlag', 1, 'n/a', 'ack_flg', 'Ack flag repeated in the inner MCU frame.', 1);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (8, 'UsbMcuPacket', 19, 20, 'Mmnn', 2, 'big', 'shortToByteArray(payload_length + 1)', 'Inner length/count field set to command payload length plus one.', 1);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (9, 'UsbMcuPacket', 21, NULL, 'Payload', NULL, 'n/a', 'command[]', 'Command-specific payload bytes listed in command_payload_fields.', 1);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (10, 'UsbMcuPacket', NULL, NULL, 'Checksum', 1, 'n/a', 'low8(sum(FrameHead bytes as signed Java bytes, ack_flg, mmnn short value, and payload bytes as signed Java bytes))', 'Checksum byte appended after payload; ConvertUtils.isComplete sums absolute offsets 16 through the byte before checksum.', 1);
INSERT INTO packet_fields (packet_field_id, packet_name, absolute_start, absolute_end, name, width_bytes, endian, value_expr, description, source_id) VALUES (11, 'RoutingEnvelope', NULL, NULL, 'TrailingRouteTag', 1, 'n/a', '0x01 head, 0x02 bottom, 0x03 both', 'Only present for command classes that allocate a ByteBuffer one byte larger than USBCommand.getMessage(). UsbMessageMrg strips this byte before bulkTransfer.', 4);
