INSERT INTO command_logic (logic_id, command_id, logic_name, logic_text, source_id) VALUES (1, 2, 'OmitMinusOneBytes', 'After assembling an ArrayList payload, getCommandBytes iterates through it and removes every byte equal to -1 before copying into the command byte array. Fields defaulting to -1 are therefore absent unless set.', 7);
