INSERT INTO command_logic (logic_id, command_id, logic_name, logic_text, source_id) VALUES (45, 82, 'WheelModePayloadSelection', 'Payload starts 01, moveWheelMode, moveWheelDirection. Mode 0x10 appends time LSB/MSB and degree; 0x02 or 0x03 appends speed and degree LSB/MSB; 0x01 appends speed, time LSB/MSB, and isCircle; 0x11 appends speed and distance LSB/MSB.', 87);
INSERT INTO command_logic (logic_id, command_id, logic_name, logic_text, source_id) VALUES (46, 23, 'HeadModePayloadSelection', 'Payload starts 02, moveHeadMode, moveHeadDirection. Mode 0x10 appends time LSB/MSB and degree; 0x02 or 0x03 appends speed and degree LSB/MSB; 0x01 appends speed; 0x21 appends horizontal and vertical absolute degree pairs; 0x22 appends horizontal/vertical relative direction and degree bytes.', 28);
INSERT INTO command_logic (logic_id, command_id, logic_name, logic_text, source_id) VALUES (47, 21, 'HandModePayloadSelection', 'Payload starts 03, moveHandMode, whichHand. Mode 0x10 appends time LSB/MSB and degree LSB/MSB; 0x02 or 0x03 appends speed, direction, and degree LSB/MSB; 0x01 appends speed and direction.', 26);
INSERT INTO command_logic (logic_id, command_id, logic_name, logic_text, source_id) VALUES (48, 8, 'AutoBatteryThresholdBranch', 'Payload is 04 05 switchMode when switchMode is 0x00; otherwise payload is 04 05 switchMode threshold.', 13);
INSERT INTO command_logic (logic_id, command_id, logic_name, logic_text, source_id) VALUES (49, 24, 'HeartBeatIntervalBranch', 'Payload is 04 08 switchMode when switchMode is 0x01; otherwise payload is 04 08 switchMode lsb msb.', 29);
INSERT INTO command_logic (logic_id, command_id, logic_name, logic_text, source_id) VALUES (50, 28, 'WhichLightEncoding', 'whichLight value 0x0A is transmitted as 0x00. Other whichLight values are transmitted unchanged.', 33);
INSERT INTO command_logic (logic_id, command_id, logic_name, logic_text, source_id) VALUES (51, 16, 'SetDataPrefix', 'setData allocates one extra byte, writes 0xA1 first, then appends caller-supplied data bytes. getData returns the data without that prefix.', 21);
INSERT INTO command_logic (logic_id, command_id, logic_name, logic_text, source_id) VALUES (52, 84, 'SetDataPrefix', 'setData allocates one extra byte, writes 0xA0 first, then appends caller-supplied data bytes. getData returns the data without that prefix.', 89);
