INSERT INTO gpio_outputs (gpio_output_id, actor_type, process_or_module, path_or_symbol, write_method, value_expr, purpose, evidence_strength, source_id) VALUES (1, 'UserProcess', 'glgps', '/sys/devices/platform/gps/power_enable', 'Broadcom GPS HAL sysfs GPIO write; configured as gpioNStdbyPath in gpsconfig.xml.', 'Writes GPIO value 0/1; strings include "GPIO %d set to %d"; gpioDelayMs is 100.', 'Powers/enables or places the Broadcom GPS on standby before using serial port /dev/ttyS2.', 'ExactConfigAndBinaryStrings', 197);
INSERT INTO gpio_outputs (gpio_output_id, actor_type, process_or_module, path_or_symbol, write_method, value_expr, purpose, evidence_strength, source_id) VALUES (2, 'UserProcess', 'glgps', '/sys/class/rfkill and gpioNResetPath', 'Broadcom GPS HAL fallback/reset GPIO path support inferred from binary strings.', 'Writes rfkill/GPIO values when configured by GPS HAL.', 'GPS reset/standby control paths supported by the binary.', 'BinaryStrings', 198);
INSERT INTO gpio_outputs (gpio_output_id, actor_type, process_or_module, path_or_symbol, write_method, value_expr, purpose, evidence_strength, source_id) VALUES (3, 'KernelModule', 'gt9xx_ts.ko', 'gpio_direction_output, __gpio_set_value, input_set_power_enable, input_set_int_enable', 'Kernel GPIO helpers inside Goodix touchscreen module.', 'Kernel driver values are not fixed in user-space firmware; driver code sets GPIO output values through kernel GPIO APIs.', 'Sets touchscreen power and interrupt GPIO lines.', 'KernelSymbols', 199);
INSERT INTO gpio_outputs (gpio_output_id, actor_type, process_or_module, path_or_symbol, write_method, value_expr, purpose, evidence_strength, source_id) VALUES (4, 'KernelModule', 'gslX680.ko', 'gpio_direction_output, __gpio_set_value, input_set_power_enable, input_set_int_enable', 'Kernel GPIO helpers inside GSL touchscreen module.', 'Kernel driver values are not fixed in user-space firmware; driver code sets GPIO output values through kernel GPIO APIs.', 'Sets touchscreen power and interrupt GPIO lines.', 'KernelSymbols', 200);
INSERT INTO gpio_outputs (gpio_output_id, actor_type, process_or_module, path_or_symbol, write_method, value_expr, purpose, evidence_strength, source_id) VALUES (5, 'KernelModule', 'gslX680new.ko', 'gpio_direction_output, __gpio_set_value, input_set_power_enable, input_set_int_enable', 'Kernel GPIO helpers inside alternate GSL touchscreen module.', 'Kernel driver values are not fixed in user-space firmware; driver code sets GPIO output values through kernel GPIO APIs.', 'Sets touchscreen power and interrupt GPIO lines.', 'KernelSymbols', 201);
INSERT INTO gpio_outputs (gpio_output_id, actor_type, process_or_module, path_or_symbol, write_method, value_expr, purpose, evidence_strength, source_id) VALUES (6, 'KernelModule', 'bcm_btlpm.ko', 'gpio_request, gpio_direction_output, __gpio_set_value', 'Bluetooth low-power module GPIO helpers.', 'Kernel driver values are not fixed in user-space firmware; driver code sets GPIO output values through kernel GPIO APIs.', 'Controls Bluetooth low-power wake/sleep GPIO lines.', 'KernelSymbols', 202);
